// Motor maximum velocities (counts/sec)
uint32_t    MOTOR_X_MAX_VEL;
uint32_t    MOTOR_Y_MAX_VEL;
uint32_t    MOTOR_Z_MAX_VEL;

// Motor maximum accelerations (counts/sec^2)
uint32_t    MOTOR_X_MAX_ACCEL;
uint32_t    MOTOR_Y_MAX_ACCEL;
uint32_t    MOTOR_Z_MAX_ACCEL;

// X-axis PID gains
float       MOTOR_X_KP;
float       MOTOR_X_KI;
float       MOTOR_X_KD;

// Y-axis PID gains
float       MOTOR_Y_KP;
float       MOTOR_Y_KI;
float       MOTOR_Y_KD;

// Z-axis PID gains
float       MOTOR_Z_KP;
float       MOTOR_Z_KI;
float       MOTOR_Z_KD;

// Motor scaling (steps per mm)
float       MOTOR_X_STEPS_PER_MM;
float       MOTOR_Y_STEPS_PER_MM;
float       MOTOR_Z_STEPS_PER_MM;

// Spindle parameters
uint32_t    SPINDLE_MAX_RPM;
uint32_t    SPINDLE_ACCEL_RPM_PER_SEC;

// Emergency stop deceleration
uint32_t    E_STOP_DECEL;

// Homing speed
uint32_t    HOMING_SPEED;

// Home positions (encoder counts)
int32_t     HOME_X_POSITION;
int32_t     HOME_Y_POSITION;
int32_t     HOME_Z_POSITION;
